# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
import sqlite3
import secrets
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)

# Function to connect to the database
def get_db_connection():
    conn = sqlite3.connect('users.db')
    conn.row_factory = sqlite3.Row
    return conn

# Route for password reset request
@app.route('/reset-password', methods=['POST'])
def reset_password():
    email = request.json.get('email')

    if not email:
        return jsonify({'error': 'Email is required'}), 400

    # Generate a random token
    token = secrets.token_urlsafe(16)

    # Connect to the database and store the token with the user's email
    conn = get_db_connection()
    try:
        conn.execute('INSERT INTO password_resets (email, token) VALUES (?, ?)', (email, token))
        conn.commit()
    except sqlite3.IntegrityError:
        return jsonify({'error': 'A reset request has already been sent for this email'}), 400
    finally:
        conn.close()

    # Send the reset link to the user's email
    send_reset_email(email, token)

    return jsonify({'message': 'Reset link has been sent to your email'})

# Function to send reset email
def send_reset_email(email, token):
    sender = "no-reply@example.com"
    receivers = [email]
    message = MIMEText(f"Click the following link to reset your password: http://example.com/reset?token={token}")
    message['Subject'] = 'Password Reset Request'
    message['From'] = sender
    message['To'] = ', '.join(receivers)

    try:
        smtpObj = smtplib.SMTP('localhost')
        smtpObj.sendmail(sender, receivers, message.as_string())
    except smtplib.SMTPException:
        print("Error: unable to send email")

if __name__ == '__main__':
    app.run(debug=True)